@rendermode InteractiveServer
@inject CascadingValueSource<ThemeInfo> ThemeSource

<span class="theme-indicator" style="color: @Theme?.AccentColor;">
    @GetIcon() @Theme?.Theme
</span>

<button class="btn btn-sm btn-outline-secondary ms-2" @onclick="CycleTheme">
    Toggle Theme
</button>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private string GetIcon() => Theme?.Theme switch
    {
        Theme.Light => "☀️",
        Theme.Dark => "🌙",
        Theme.System => "💻",
        _ => "☀️"
    };

    private async Task CycleTheme()
    {
        var next = Theme?.Theme switch
        {
            Theme.Light => Theme.Dark,
            Theme.Dark => Theme.System,
            Theme.System => Theme.Light,
            _ => Theme.Light
        };

        await ThemeSource.NotifyChangedAsync(
            new ThemeInfo(next, Theme?.AccentColor ?? ThemeInfo.Default.AccentColor));
    }
}

@page "/settings"
@rendermode InteractiveServer
@inject CascadingValueSource<ThemeInfo> ThemeSource

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-4" style="max-width: 500px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="mb-3">
            <label class="form-label">Color Mode</label>
            <select class="form-select" value="@currentTheme" @onchange="OnThemeChanged">
                @foreach (var t in Enum.GetValues<Theme>())
                {
                    <option value="@t">@t</option>
                }
            </select>
        </div>

        <div class="mb-3">
            <label class="form-label">
                Accent Color
                <span class="ms-2 rounded-circle d-inline-block"
                      style="width:16px; height:16px; background:@currentAccent; vertical-align:middle;">
                </span>
            </label>
            <input type="color" class="form-control form-control-color"
                   value="@currentAccent" @onchange="OnAccentChanged" />
        </div>

        <div class="alert alert-info mt-3">
            <strong>Current:</strong> @currentTheme mode, accent
            <span style="color: @currentAccent;">@currentAccent</span>
        </div>
    </div>
</div>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private Theme currentTheme;
    private string currentAccent = ThemeInfo.Default.AccentColor;

    protected override void OnParametersSet()
    {
        if (Theme is not null)
        {
            currentTheme = Theme.Theme;
            currentAccent = Theme.AccentColor;
        }
    }

    private async Task OnThemeChanged(ChangeEventArgs e)
    {
        if (Enum.TryParse<Theme>(e.Value?.ToString(), out var parsed))
        {
            currentTheme = parsed;
            await ThemeSource.NotifyChangedAsync(new ThemeInfo(currentTheme, currentAccent));
        }
    }

    private async Task OnAccentChanged(ChangeEventArgs e)
    {
        currentAccent = e.Value?.ToString() ?? currentAccent;
        await ThemeSource.NotifyChangedAsync(new ThemeInfo(currentTheme, currentAccent));
    }
}

